  static List<ServerServiceInfo> listFromJson(dynamic json, {bool growable = false,}) {
    final result = <ServerServiceInfo>[];
    if (json is List && json.isNotEmpty) {
      for (final row in json) {
        final value = ServerServiceInfo.fromJson(row);
        if (value != null) {
          result.add(value);
        }
      }
    }
    return result.toList(growable: growable);
  }

  static Map<String, ServerServiceInfo> mapFromJson(dynamic json) {
    final map = <String, ServerServiceInfo>{};
    if (json is Map && json.isNotEmpty) {
      json = json.cast<String, dynamic>(); // ignore: parameter_assignments
      for (final entry in json.entries) {
        final value = ServerServiceInfo.fromJson(entry.value);
        if (value != null) {
          map[entry.key] = value;
        }
      }
    }
    return map;
  }

  // maps a json object with a list of ServerServiceInfo-objects as value to a dart map
  static Map<String, List<ServerServiceInfo>> mapListFromJson(dynamic json, {bool growable = false,}) {
    final map = <String, List<ServerServiceInfo>>{};
    if (json is Map && json.isNotEmpty) {
      // ignore: parameter_assignments
      json = json.cast<String, dynamic>();
      for (final entry in json.entries) {
        map[entry.key] = ServerServiceInfo.listFromJson(entry.value, growable: growable,);
      }
    }
    return map;
  }

